#include<bits/stdc++.h>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
using namespace std;
const int N=505;
bool f1;
int dp[N][N][N],t[N],s[N],n,a[N],C[N][N],fac[N],m;
char lm[N];int fre[N];
bool f2;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int Mod=998244353;
inline void DN(int &x){x>=Mod?x-=Mod:0;}
int main()
{
//	printf("Mem :: %.6lf\n",1.*(&f1-&f2)/1024/1024);
	n=read();m=read();
	fac[0]=1;C[0][0]=1;
	rep(1,n,i)
	{
		C[i][0]=C[i][i]=1;
		rep(1,i-1,j)DN(C[i][j]=C[i-1][j]+C[i-1][j-1]);
		fac[i]=1ll*fac[i-1]*i%Mod;
	}
	scanf("%s",lm+1);
	rep(1,n,i)++t[a[i]=read()];
	s[n-1]=t[n];
	drep(n-2,0,i)s[i]=s[i+1]+t[i+1];
//	printf("s :: ");rep(0,n,i)printf("%d ",s[i]);puts("");
//	printf("t :: ");rep(0,n,i)printf("%d ",t[i]);puts("");
//	printf("fac :: ");rep(0,n,i)printf("%d ",fac[i]);puts("");
//	printf("C[%d][%d] = %d\n",3,2,C[3][2]);
	dp[0][0][0]=1;
	rep(1,n,i)
	{
		rep(0,min(n-m,i-1),j)
		{
			rep(0,i-1,k)
			{
				int g=dp[i-1][j][k];
				if(lm[i]=='1')
				{
					DN(dp[i][j][k+1]+=g);
				}
				else
				{
					drep(min(k+1,t[j+1]),0,l)
					{
						int res=g;
						res=1ll*res*C[k+1][l]%Mod;
						res=1ll*res*C[t[j+1]][l]%Mod;
						res=1ll*res*fac[l]%Mod;
//						printf("(%d,%d,%d) --%d--> (%d,%d,%d)\n",i-1,j,k,res,i,j+1,k+1-l);
						DN(dp[i][j+1][k+1-l]+=res);
					}
				}
				drep(min(k,t[j+1]),0,l)
				{
					int res=g;
					res=1ll*res*((n-s[j])-i+k+1+Mod)%Mod;
//					printf("(%d,%d,%d) --%d--> (%d,%d,%d)\n",i-1,j,k,res,i,j+1,k-l);
					res=1ll*res*C[k][l]%Mod;
//					printf("(%d,%d,%d) --%d--> (%d,%d,%d)\n",i-1,j,k,res,i,j+1,k-l);
					res=1ll*res*C[t[j+1]][l]%Mod;
//					printf("(%d,%d,%d) --%d--> (%d,%d,%d) %d %d %d\n",i-1,j,k,res,i,j+1,k-l,t[j+1],l,C[t[j+1]][l]);
					res=1ll*res*fac[l]%Mod;
//					printf("(%d,%d,%d) --%d--> (%d,%d,%d)\n",i-1,j,k,res,i,j+1,k-l);
					DN(dp[i][j+1][k-l]+=res);
				}
			}
		}
	}
	int ans=0;rep(0,n-m,i)
	{
		ans=(1ll*dp[n][i][s[i]]*fac[s[i]]+ans)%Mod;
	}
	printf("%d\n",ans);
}
